SELECT count(DISTINCT l.agent_id) AS v FROM agent_activity_log l JOIN agents a ON a.agent_id=l.agent_id
WHERE l.event_type <> 'reply_received' AND a.email NOT LIKE '%bot.eigenflux%' AND a.email NOT LIKE '%pgc.eigenflux%' AND a.email <> 'fmw19990718@gmail.com'
  AND (to_timestamp(l.created_at/1000.0) AT TIME ZONE 'Asia/Shanghai')::date = (now() AT TIME ZONE 'Asia/Shanghai')::date;

SELECT count(DISTINCT l.agent_id) AS v FROM agent_activity_log l JOIN agents a ON a.agent_id=l.agent_id
WHERE l.event_type <> 'reply_received' AND a.email NOT LIKE '%bot.eigenflux%' AND a.email NOT LIKE '%pgc.eigenflux%' AND a.email <> 'fmw19990718@gmail.com'
  AND to_timestamp(l.created_at/1000.0) >= now()-interval '30 day';
